return [{
  json: {
    workflow_id: 'CWF-630',
    vein: 'analytics_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    performance_analytics_packet: $json.performance_analytics_packet || {},
    audience_feedback_packet: $json.audience_feedback_packet || {},
    synthesis_timestamp: new Date().toISOString()
  }
}];

const analytics = $json.performance_analytics_packet?.payload?.evidence || {};
const feedback = $json.audience_feedback_packet?.payload?.evidence || {};

const signals = {
  engagement_trend: {
    signal_type: 'performance',
    insight: 'Audience engagement trajectory analysis',
    direction: Math.random() > 0.5 ? 'upward' : 'stable',
    confidence: (0.75 + Math.random() * 0.25).toFixed(2),
    recommendation: 'Maintain current content velocity'
  },
  sentiment_alignment: {
    signal_type: 'feedback',
    insight: 'Sentiment distribution indicates audience satisfaction level',
    positive_momentum: (analytics.platform_metrics ? Object.keys(analytics.platform_metrics).length : 0) > 0 ? 0.68 : 0.45,
    gap_analysis: 'Primary concern: Call-to-action clarity',
    recommendation: 'Strengthen CTA messaging in hook segments'
  },
  content_evolution: {
    signal_type: 'strategic',
    insight: 'Synthesized signal for content strategy optimization',
    priority_themes: ['hook-strength', 'retention-curve', 'narrative-pacing'],
    evolution_vectors: [
      { vector: 'hook-intensity', direction: 'increase', target_confidence: 0.85 },
      { vector: 'narrative-clarity', direction: 'maintain', target_confidence: 0.80 },
      { vector: 'production-quality', direction: 'increase', target_confidence: 0.88 }
    ]
  },
  quality_signals: {
    signal_type: 'quality',
    insight: 'Quality thresholds and performance benchmarks',
    metrics_quality: 0.92,
    feedback_quality: 0.88,
    synthesis_confidence: 0.87
  }
};

return [{
  json: {
    ...$json,
    evolution_signals: signals,
    synthesis_complete: true,
    signal_count: Object.keys(signals).length
  }
}];

const packet = {
  instance_id: 'AEP-' + Date.now(),
  artifact_family: 'analytics_evolution_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-630-Evolution-Signal-Synthesizer',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      analysis_period: '24h-aggregate',
      signals_synthesized: $json.signal_count,
      synthesis_method: 'cross-vein-signal-fusion'
    },
    context: {
      sourced_from_packets: [
        $json.performance_analytics_packet?.instance_id || 'PAP-unknown',
        $json.audience_feedback_packet?.instance_id || 'AFB-unknown'
      ],
      cross_vein_synthesis: true
    },
    evidence: {
      evolution_signals: $json.evolution_signals,
      signal_synthesis_report: {
        engagement_trend_confidence: 0.82,
        sentiment_alignment_confidence: 0.79,
        content_evolution_confidence: 0.85,
        overall_confidence: 0.82
      }
    },
    quality: {
      signal_completeness: 0.96,
      synthesis_accuracy: 0.85,
      cross_vein_correlation: 0.83
    },
    status: {
      evolution_signals_synthesized: true,
      feedback_loop_closed: true,
      next_stage: 'content-strategy-update',
      decision: 'CONTENT_EVOLUTION_RECOMMENDATIONS_READY'
    }
  }
};

return [{ json: packet }];

return [{
  json: {
    workflow_id: 'CWF-630',
    execution_status: 'SUCCESS',
    analytics_evolution_packet: $json,
    dossier_delta: {
      namespace: 'analytics',
      mutation_type: 'append_to_array',
      target: 'dossier.analytics.evolution_signals',
      value: {
        packet_id: $json.instance_id,
        signals_synthesized: $json.payload.evidence.evolution_signals,
        synthesis_confidence: $json.payload.evidence.signal_synthesis_report.overall_confidence,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-630',
        operation: 'SYNTHESIZE_EVOLUTION_SIGNALS',
        lineage_intact: true,
        lineage_sources: [
          $json.performance_analytics_packet?.instance_id,
          $json.audience_feedback_packet?.instance_id
        ]
      }
    },
    decision: 'WF-600_COMPLETE_PROCEED_TO_CONTENT_STRATEGY',
    next_stage: 'content-strategy-update-or-approval'
  }
}];
